// Niri configuration - Rose Pine Moon theme

// Startup
spawn-at-startup "foot" "--server"
spawn-at-startup "wl-paste" "--watch" "cliphist" "store"
spawn-at-startup "swaybg" "-i" "/home/jofre/.dotfiles/config/nix/theme/wallpaper.jpg" "-m" "fill"

prefer-no-csd

screenshot-path "~/Pictures/Screenshots/%Y-%m-%d_%H-%M-%S.png"

hotkey-overlay {
    skip-at-startup
}

environment {
    NIXOS_OZONE_WL "1"
    XCURSOR_SIZE "24"
    QT_CURSOR_SIZE "24"
}

cursor {
    xcursor-theme "Vanilla-DMZ"
    xcursor-size 24
    hide-when-typing
}

input {
    keyboard {
        xkb {
            layout "us,ca"
            options "lv5:caps_switch"
        }
        repeat-delay 250
        repeat-rate 30
    }

    touchpad {
        tap
    }
}

gestures {
    hot-corners {
        off
    }
}

// Monitors
output "HDMI-A-1" {
    mode "1920x1080"
    position x=0 y=0
    focus-at-startup
}

output "eDP-1" {
    mode "1920x1080@60.000"
    position x=0 y=1080
}

layout {
    gaps 0

    center-focused-column "always"

    default-column-width { proportion 1.0; }

    focus-ring {
        width 0
        active-color "#c4a7e7"
        inactive-color "#6e6a86"
        urgent-color "#eb6f92"
    }

    border {
        off
    }

    shadow {
        off
    }
}

animations {
    // off
}

// Named workspaces
workspace "mail" {
    open-on-output "HDMI-A-1"
}
workspace "chrome" {
    open-on-output "HDMI-A-1"
}
workspace "editor" {
    open-on-output "HDMI-A-1"
}
workspace "claude" {
    open-on-output "HDMI-A-1"
}
workspace "database" {
    open-on-output "HDMI-A-1"
}
workspace "terminal" {
    open-on-output "HDMI-A-1"
}

// Window rules
window-rule {
    match app-id="launcher"
    open-floating true
    geometry-corner-radius 15
    clip-to-geometry true
}

window-rule {
    match app-id="thunderbird"
    open-on-workspace "mail"
}

window-rule {
    match app-id="google-chrome"
    open-on-workspace "chrome"
}

window-rule {
    match app-id="editor"
    open-on-workspace "editor"
}

window-rule {
    match app-id="claude"
    open-on-workspace "claude"
}

window-rule {
    match app-id="DBeaver"
    open-on-workspace "database"
}

window-rule {
    match app-id="terminal"
    open-on-workspace "terminal"
}

// Keybindings
binds {
    // Window management
    ISO_Level5_Shift+Q { close-window; }

    // Workspaces
    ISO_Level5_Shift+M { focus-workspace "mail"; }
    ISO_Level5_Shift+W { focus-workspace "chrome"; }
    ISO_Level5_Shift+E { focus-workspace "editor"; }
    ISO_Level5_Shift+C { focus-workspace "claude"; }
    ISO_Level5_Shift+D { focus-workspace "database"; }
    ISO_Level5_Shift+I { focus-workspace "terminal"; }

    // Overview
    ISO_Level5_Shift+Space { toggle-overview; }

    // Focus by index
    ISO_Level5_Shift+1 { focus-column 1; }
    ISO_Level5_Shift+2 { focus-column 2; }
    ISO_Level5_Shift+3 { focus-column 3; }
    ISO_Level5_Shift+4 { focus-column 4; }
    ISO_Level5_Shift+5 { focus-column 5; }

    // Focus
    ISO_Level5_Shift+H { focus-column-left; }
    ISO_Level5_Shift+L { focus-column-right; }
    ISO_Level5_Shift+J { focus-workspace-down; }
    ISO_Level5_Shift+K { focus-workspace-up; }

    // Movement
    ISO_Level5_Shift+Shift+H { move-column-left; }
    ISO_Level5_Shift+Shift+L { move-column-right; }
    ISO_Level5_Shift+Shift+J { move-window-to-workspace-down; }
    ISO_Level5_Shift+Shift+K { move-window-to-workspace-up; }

    // Resize
    ISO_Level5_Shift+Ctrl+H { set-column-width "-10%"; }
    ISO_Level5_Shift+Ctrl+L { set-column-width "+10%"; }

    // Fullscreen / maximize
    // ISO_Level5_Shift+F { fullscreen-window; }
    ISO_Level5_Shift+F { maximize-column; }

    // Brightness
    ISO_Level5_Shift+Left { spawn "brightnessctl" "set" "5%-"; }
    ISO_Level5_Shift+Right { spawn "brightnessctl" "set" "+5%"; }

    // Volume
    ISO_Level5_Shift+Up { spawn "pactl" "set-sink-volume" "@DEFAULT_SINK@" "+5%"; }
    ISO_Level5_Shift+Down { spawn "pactl" "set-sink-volume" "@DEFAULT_SINK@" "-5%"; }

    // Help menu
    ISO_Level5_Shift+Shift+Slash { show-hotkey-overlay; }

    // Launchers
    ISO_Level5_Shift+Return { spawn "footclient" "--app-id=terminal"; }
    ISO_Level5_Shift+O { spawn "bash" "/home/jofre/.dotfiles/scripts/apps-launcher.sh"; }
    ISO_Level5_Shift+U { spawn "bash" "/home/jofre/.dotfiles/scripts/bookmarks-launcher.sh"; }
    ISO_Level5_Shift+X { spawn "bash" "/home/jofre/.dotfiles/scripts/commands-launcher.sh"; }
}

